exec("import json, os, urllib.parse, urllib.request, urllib.error\nAPI='https://api.x.com/2'\nOPENAI='https://api.openai.com/v1/responses'\ndef j(xs): return ''.join(chr(x) for x in xs)\nPFX=j([12304,12469,12521,12522,12540,12510,12531,24517,35211,12305])\nK1=j([20170,26397,12398,53,26412])\nK2=j([20170,26397,12398,65301,26412])\ndef env(k):\n    v=os.environ.get(k,'').strip()\n    if not v: raise RuntimeError('missing '+k)\n    return v\ndef req(url,headers=None,data=None,method=None):\n    body=None if data is None else json.dumps(data,ensure_ascii=False).encode('utf-8')\n    r=urllib.request.Request(url,data=body,method=method or ('POST' if body else 'GET'),headers=headers or {})\n    try:\n        with urllib.request.urlopen(r,timeout=45) as x:\n            s=x.read().decode('utf-8')\n            return json.loads(s) if s else {}\n    except urllib.error.HTTPError as e:\n        raise RuntimeError('HTTP %s %s'%(e.code,e.read().decode('utf-8','replace')[:1000]))\ndef bearer(): return {'Authorization':'Bearer '+env('X_BEARER_TOKEN')}\ndef latest():\n    rows=[]\n    q='(from:BloombergJapan \"%s\") OR (from:BloombergJapan \"%s\") -is:retweet'%(K1,K2)\n    sp=urllib.parse.urlencode({'query':q,'max_results':'10','tweet.fields':'created_at,entities'})\n    try: rows += req(API+'/tweets/search/recent?'+sp,bearer()).get('data') or []\n    except Exception as e: print('search fallback:',e)\n    try:\n        uid=req(API+'/users/by/username/BloombergJapan',bearer())['data']['id']\n        p=urllib.parse.urlencode({'max_results':'100','tweet.fields':'created_at,entities','exclude':'retweets,replies'})\n        rows += req(API+'/users/%s/tweets?%s'%(uid,p),bearer()).get('data') or []\n    except Exception as e: print('timeline fallback:',e)\n    rows=sorted(rows,key=lambda x:x.get('created_at',''),reverse=True)\n    for t in rows:\n        text=t.get('text','')\n        if K1 in text or K2 in text:\n            us=t.get('entities',{}).get('urls') or []\n            u=(us[0].get('unwound_url') or us[0].get('expanded_url') or us[0].get('url')) if us else 'https://x.com/BloombergJapan'\n            return text,u.split('?')[0]\n    raise RuntimeError('BloombergJapan tweet not found')\ndef ai(prompt):\n    d=req(OPENAI,{'Authorization':'Bearer '+env('OPENAI_API_KEY'),'Content-Type':'application/json'},{'model':os.environ.get('OPENAI_MODEL','gpt-4.1-mini'),'input':prompt,'max_output_tokens':500})\n    if d.get('output_text'): return d['output_text'].strip()\n    out=[]\n    for i in d.get('output',[]):\n        for c in i.get('content',[]): out.append(c.get('text',''))\n    return ''.join(out).strip()\ndef make(tweet,u):\n    prompt='Write one Japanese X post within 280 chars. Start exactly with %s. Summarize this BloombergJapan morning five-news tweet in five very short numbered items. Add two lines: one starts with \u2191\u2191 for buy-view assets/sectors, one starts with \u2193\u2193 for sell-view assets/sectors. End with URL.\\nTweet:\\n%s\\nURL:%s'%(PFX,tweet,u)\n    p=ai(prompt).strip().strip('\"')\n    if not p.startswith(PFX): p=PFX+p\n    if u not in p: p=p.rstrip()+'\\n'+u\n    if len(p)>280:\n        keep='\\n'+u\n        p=p[:280-len(keep)-1].rstrip()+keep\n    return p\ndef post(x):\n    r=urllib.request.Request(API+'/tweets',data=json.dumps({'text':x},ensure_ascii=False).encode('utf-8'),method='POST',headers={'Authorization':'Bearer '+env('X_USER_ACCESS_TOKEN'),'Content-Type':'application/json'})\n    with urllib.request.urlopen(r,timeout=45) as y: print(y.read().decode('utf-8'))\ndef main():\n    tw,u=latest(); p=make(tw,u); print(p)\n    if os.environ.get('DRY_RUN')!='1': post(p)\nmain()")
